{
  "summary": "This paper presents a comprehensive empirical benchmark evaluating continual learning (CL) methods across multiple pre-trained language models (PLMs) and NLP tasks. It introduces a novel prototype-based layer-wise probing technique to analyze catastrophic forgetting and transfer dynamics within PLMs, revealing insights on method effectiveness and internal layer robustness.",
  "strengths": [
    {
      "point": "Comprehensive empirical benchmark covering diverse CL settings, datasets, methods, and PLMs",
      "evidence": "The study evaluates six CL schemes (Vanilla, Joint, EWC, HAT, ER, DERPP) across three NLP datasets (CLINC150, Maven, WebRED) and five PLMs (ALBERT, BERT, GPT2, RoBERTa, XLNET) under Task-IL and Class-IL settings."
    },
    {
      "point": "Novel prototype-based layer-wise probing method to analyze representational forgetting",
      "evidence": "The paper introduces a probing technique that measures representational ability at each PLM layer, uncovering that the classifier layer is a major forgetting bottleneck and that inner layers vary in robustness across PLMs."
    },
    {
      "point": "Insightful findings on the superiority of rehearsal-based methods and PLM robustness",
      "evidence": "Rehearsal-based methods ER and DERPP outperform regularization and dynamic architecture methods, with BERT identified as the most robust PLM overall; ALBERT’s parameter sharing leads to more fragile hidden layers."
    },
    {
      "point": "Open release of code and datasets to facilitate reproducibility and future research",
      "evidence": "The authors commit to releasing all code and data as open-access resources."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison with recent and advanced continual learning methods",
      "evidence": "The paper omits parameter-efficient fine-tuning approaches like AdapterFusion, prompt tuning (e.g., L2P), and meta-continual learning frameworks (OML, ANML), which could strengthen novelty and practical relevance."
    },
    {
      "point": "Lack of justification for PLM selection and exclusion of larger or more recent models",
      "evidence": "Models such as DeBERTa, T5, or GPT-3 variants are not included, and the rationale for their exclusion is not clearly stated, limiting generalizability."
    },
    {
      "point": "Insufficient ablation studies on critical hyperparameters in rehearsal methods",
      "evidence": "No analysis on replay buffer size or sampling strategies is provided, leaving unclear whether performance gains stem from method design or buffer management."
    },
    {
      "point": "Evaluation limited by dataset bias and simplified task definitions",
      "evidence": "Datasets assume clear task boundaries and label exclusivity, which may not reflect real-world continual learning scenarios involving overlapping classes or domain shifts."
    },
    {
      "point": "Metrics used do not fully capture continual learning complexity",
      "evidence": "The study relies mainly on average accuracy, forward and backward transfer, omitting per-task forgetting curves, memory overhead, and stability-plasticity trade-offs."
    },
    {
      "point": "Joint training baseline treated as an unrealistic upper bound without discussion",
      "evidence": "The impracticality of Joint training in continual learning scenarios is not acknowledged, nor are more realistic upper bounds considered."
    },
    {
      "point": "Reproducibility hindered by insufficient hyperparameter and methodological details",
      "evidence": "Critical training details such as learning rates, batch sizes, epochs, optimizer choices, and prototype-based probing implementation are not fully described."
    },
    {
      "point": "Clarity issues regarding task definitions and practical implications",
      "evidence": "Ambiguity exists in Task-IL vs. Class-IL definitions and the availability of task labels during inference, affecting method applicability and result interpretation."
    },
    {
      "point": "Limited discussion on scalability to larger numbers of tasks and domain shifts",
      "evidence": "The paper does not address how methods perform with many tasks or under non-stationary data distributions common in real-world CL."
    },
    {
      "point": "Generalisability restricted to English classification tasks without multilingual or generation evaluation",
      "evidence": "No experiments or discussion on other languages, generation, or structured prediction tasks are provided."
    },
    {
      "point": "No detailed analysis of memory and computational constraints beyond training time",
      "evidence": "Memory usage of replay buffers and computational overheads critical for deployment are not profiled or discussed."
    }
  ],
  "questions": [
    {
      "question": "How do newer parameter-efficient and meta-continual learning methods compare to classical baselines in NLP continual learning?",
      "motivation": "Including these methods could reveal more effective strategies and improve the practical relevance of CL research in NLP."
    },
    {
      "question": "What are the effects of pretraining objectives and data diversity on catastrophic forgetting and transfer in PLMs?",
      "motivation": "Understanding this could guide the design of PLMs better suited for continual learning."
    },
    {
      "question": "How can rehearsal buffer management (size, sampling) be optimized to maximize forgetting mitigation?",
      "motivation": "Clarifying this would help disentangle method design from buffer effects and improve rehearsal-based methods."
    },
    {
      "question": "How do CL methods and PLMs scale to longer task sequences and more realistic domain-shift scenarios?",
      "motivation": "Real-world continual learning involves many tasks and evolving data distributions, so scalability and robustness are critical."
    },
    {
      "question": "Can layer-wise robustness insights be leveraged to design more efficient and effective continual learning strategies?",
      "motivation": "Exploiting robust layers for feature extraction or selective fine-tuning could reduce computation and memory overhead."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
